  --df-file-uploader-tile-icon-size: var(--df-file-uploader-tile-icon-size-md);
  --df-file-uploader-tile-radius: var(--radius-lg);
  --df-leading-code: 1.7;

  --success: oklch(0.55 0.14 145);
  --warning: oklch(0.7 0.14 75);

  /* TextMark wash and stroke defaults. */
  --df-text-mark-yellow: color-mix(
    in oklch,
    var(--df-yellow-green-90) 82%,
    transparent
  );
  --df-text-mark-pink: color-mix(
    in oklch,
    var(--df-magenta-200) 68%,
    transparent
  );
  --df-text-mark-blue: var(--df-blue-400);
  --df-text-mark: var(--df-text-mark-yellow);
  --df-text-mark-foreground: var(--foreground);

  --focus-ring: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
  --focus-ring-lg: 0 0 0 4px color-mix(in oklch, var(--ring) 50%, transparent);
  --focus-ring-error: 0 0 0 3px color-mix(in oklch, var(--destructive) 20%, transparent);

  --z-base: 0;
  --z-raised: 1;
  --z-sticky: 10;
  --z-dock: 20;
  --z-nav: 30;
  --z-header: 40;
  --z-overlay: 50;
  --z-toast: 60;

  --opacity-disabled: var(--df-opacity-50);
  --opacity-muted: var(--df-opacity-70);
  --opacity-subtle: var(--df-opacity-75);

  /* Shared form-field disabled surface (Input, Select, and peers). */
  --df-field-disabled-bg: var(--muted);
  --df-field-disabled-border: var(--border);
  --df-field-disabled-fg: var(--muted-foreground);

  --overlay-bg: color-mix(in oklch, black 50%, transparent);
  --overlay-fg: color-mix(in oklch, white 88%, transparent);
  --overlay-border: color-mix(in oklch, white 10%, transparent);
  --overlay-shadow: var(--df-shadow-overlay);
  --overlay-blur: var(--df-blur-overlay);
  --overlay-item-fg: color-mix(in oklch, white 82%, transparent);
  --overlay-item-fg-active: white;
  --overlay-item-hover-bg: color-mix(in oklch, white 10%, transparent);
  --overlay-item-on-bg: color-mix(in oklch, white 12%, transparent);
  --overlay-solid-bg: white;
  --overlay-solid-fg: oklch(0.2 0 0);
  --overlay-solid-hover-bg: color-mix(in oklch, white 88%, oklch(0.85 0 0));
  --overlay-divider: color-mix(in oklch, white 15%, transparent);

  --df-floating-controls-padding-none: 0;
  --df-floating-controls-padding-sm: calc(0.5 * var(--spacing-unit));
  --df-floating-controls-padding-default: calc(1 * var(--spacing-unit));
  --df-floating-controls-padding-lg: calc(1.5 * var(--spacing-unit));
  --df-floating-controls-padding-2xl: calc(2 * var(--spacing-unit));
  --df-floating-controls-padding: var(--df-floating-controls-padding-default);
  --df-floating-controls-radius: var(--radius-xl);

  --overlay-hint-radius: var(--radius-md);
  --overlay-hint-default-bg: color-mix(in oklch, white 78%, transparent);
  --overlay-hint-default-border: color-mix(in oklch, black 10%, transparent);
  --overlay-hint-default-fg: color-mix(in oklch, black 72%, transparent);
  --overlay-hint-default-shadow: 0 10px 28px
    color-mix(in oklch, black var(--df-shadow-intensity-md), transparent);
  --overlay-hint-default-blur: var(--overlay-blur);
  --overlay-hint-default-dark-bg: var(--overlay-bg);
  --overlay-hint-default-dark-border: var(--overlay-border);
  --overlay-hint-default-dark-fg: var(--overlay-item-fg);
  --overlay-hint-default-dark-shadow: var(--overlay-shadow);
  --overlay-hint-default-dark-blur: var(--overlay-blur);
  --overlay-hint-muted-bg: var(--muted);
  --overlay-hint-muted-border: var(--border);
  --overlay-hint-muted-fg: var(--muted-foreground);
  --overlay-hint-muted-shadow: none;
  --overlay-hint-muted-blur: 0px;
  --overlay-hint-marquee-bg: color-mix(in oklch, white 88%, transparent);
  --overlay-hint-marquee-border: color-mix(in oklch, black 10%, transparent);
  --overlay-hint-marquee-fg: color-mix(in oklch, black 62%, transparent);
  --overlay-hint-marquee-shadow: 0 10px 28px
    color-mix(in oklch, black var(--df-shadow-intensity-md), transparent);
  --overlay-hint-marquee-blur: var(--overlay-blur);
  --overlay-hint-marquee-action-bg: color-mix(in oklch, black 8%, transparent);
  --overlay-hint-marquee-action-fg: color-mix(in oklch, black 72%, transparent);
  --overlay-hint-marquee-dark-bg: var(--overlay-bg);
  --overlay-hint-marquee-dark-border: var(--overlay-border);
  --overlay-hint-marquee-dark-fg: var(--overlay-item-fg);
  --overlay-hint-marquee-dark-shadow: var(--overlay-shadow);
  --overlay-hint-marquee-dark-blur: var(--overlay-blur);
  --overlay-hint-marquee-dark-action-bg: color-mix(in oklch, white 12%, transparent);
  --overlay-hint-marquee-dark-action-fg: var(--overlay-item-fg);
  --overlay-hint-marquee-width: 12rem;
  --overlay-hint-marquee-duration: 18s;
  --overlay-hint-marquee-gap: calc(4 * var(--spacing-unit, 0.25rem));
  --overlay-hint-marquee-fade: 0.75rem;
  /* Mask stops for fade edges (opaque shows, clear hides). */
  --df-mask-opaque: #000;
  --df-mask-clear: transparent;
  --overlay-hint-marquee-mask: linear-gradient(
    90deg,
    var(--df-mask-clear) 0,
    var(--df-mask-opaque) var(--overlay-hint-marquee-fade),
    var(--df-mask-opaque) calc(100% - var(--overlay-hint-marquee-fade)),
    var(--df-mask-clear) 100%
  );

  --spectrum-text-color-1: var(--df-rose-470);
  --spectrum-text-color-2: var(--df-violet-670);
  --spectrum-text-color-3: var(--df-blue-530);
  --spectrum-text-color-4: var(--df-azure-330);
  --spectrum-text-duration: 10s;
  --spectrum-text-ease: ease-in-out;
  --spectrum-text-background-size: 200% auto;

  --df-popover-width-sm: 14rem;
  --df-popover-width: 18rem;
  --df-popover-width-lg: 22rem;
  --df-popover-width-safe: min(
    var(--df-popover-width),
    calc(100vw - 8 * var(--spacing-unit))
  );
  --df-popover-arrow-size: calc(2 * var(--spacing-unit));
  --df-popover-arrow-offset: var(--df-tooltip-arrow-offset);
  --df-popover-arrow-align-nudge: var(--df-tooltip-arrow-align-nudge);
  --df-dialog-width: min(
    36rem,
    calc(100vw - 8 * var(--spacing-unit))
  );
  --df-dialog-max-height: min(
    40rem,
    calc(100vh - 8 * var(--spacing-unit))
  );
  --df-dialog-scrim: color-mix(in oklch, black 45%, transparent);
  --df-tooltip-max-width: 16rem;
  --df-tooltip-max-width-detailed: 18rem;
  --df-menu-min-width: 9rem;
  --df-menu-max-height: 24rem;
  --df-submenu-min-width: 18rem;
  --df-submenu-max-height: 28rem;
  /* Toast and Toaster chrome. */
  --df-toaster-width: 22rem;
  --df-toaster-gap: calc(2 * var(--spacing-unit));
  --df-toaster-inset: calc(4 * var(--spacing-unit));
  --df-toaster-viewport-gutter: calc(8 * var(--spacing-unit));
  --df-toast-width: 100%;
  --df-toast-height: auto;
  --df-toast-min-height: auto;
  --df-toast-bg: var(--popover);
  --df-toast-fg: var(--popover-foreground);
  --df-toast-border: var(--border);
  --df-toast-border-width: var(--border-width-hairline);
  --df-toast-radius: var(--radius);
  --df-toast-shadow: var(--df-shadow-lg);
  --df-toast-padding-block: calc(3 * var(--spacing-unit));
  --df-toast-padding-inline: calc(3.5 * var(--spacing-unit));
  --df-toast-gap: calc(2.5 * var(--spacing-unit));
  --df-toast-icon-success: var(--success);
  --df-toast-icon-error: var(--destructive);
  --df-toast-icon-warning: var(--warning);
  --df-toast-icon-info: var(--muted-foreground);
  --df-toast-close-size: var(--df-control-height-2xs);
  --df-toast-close-fg: var(--muted-foreground);
  --df-toast-close-hover-bg: var(--muted);
  --df-toast-close-hover-fg: var(--foreground);
  --df-toast-action-fg: var(--foreground);
  --df-toast-action-hover-fg: var(--foreground);
  --df-toast-action-hover-bg: var(--muted);
  --df-toast-action-padding-inline: calc(1.5 * var(--spacing-unit));
  --df-toast-action-radius: var(--radius-md);
  --df-toast-action-font-size: var(--df-text-sm);
  --df-toast-action-font-weight: var(--df-font-weight-medium);

  /* Drag and drop chrome. */
  --df-dnd-lift-scale: 1.02;
  --df-dnd-drop-line-thickness: var(--border-width-thick);
  --df-dnd-drop-line-color: var(--foreground);
  --df-dnd-drop-line-inset-inline: calc(1 * var(--spacing-unit));
  --df-dnd-placeholder-opacity: var(--opacity-muted);
  --df-dnd-placeholder-border-width: var(--border-width-hairline);
  --df-dnd-placeholder-border-color: var(--border);
  --df-dnd-placeholder-bg: var(--muted);
  --df-dnd-overlay-z: var(--z-overlay);
  --df-dnd-overlay-radius: var(--radius-lg);
  --df-dnd-overlay-shadow: var(--df-shadow-overlay);

  --sidebar: var(--df-neutral-20, var(--df-neutral-50));
  --sidebar-foreground: var(--df-neutral-900);
  --sidebar-primary: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-primary-foreground: var(--df-neutral-0);
  --sidebar-accent: var(--df-neutral-50);
  --sidebar-accent-foreground: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-border: var(--df-neutral-100);
  --sidebar-ring: var(--df-neutral-400);
}

[data-df-color-scale="compact"] {
  --primary: var(--df-neutral-900);
  --primary-foreground: var(--df-neutral-0);
  --secondary-foreground: var(--df-neutral-900);
  --accent-foreground: var(--df-neutral-900);
  --sidebar: var(--df-neutral-50);
  --sidebar-primary: var(--df-neutral-900);
  --sidebar-accent-foreground: var(--df-neutral-900);
}

/* Control and affordance sizes for host data-df-density. */
:root,
[data-df-density="cozy"] {
  --df-control-optical-shift: 1px;
  --df-control-height-2xs: calc(6 * var(--spacing-unit));
  --df-control-height-xs: calc(7 * var(--spacing-unit));
  --df-control-height-sm: calc(8 * var(--spacing-unit));
  --df-control-height-md: calc(9 * var(--spacing-unit));
  --df-control-height-lg: calc(10 * var(--spacing-unit));
  --df-control-height-xl: calc(11 * var(--spacing-unit));
  --df-control-height-2xl: calc(12 * var(--spacing-unit));
  --df-affordance-size-2xs: calc(2.5 * var(--spacing-unit));
  --df-affordance-size-xs: calc(3 * var(--spacing-unit));
