  --df-command-palette-section-padding-inline: calc(3 * var(--spacing-unit));
  --df-command-palette-section-padding-block: calc(2 * var(--spacing-unit));
  --df-command-palette-item-padding-inline: calc(3 * var(--spacing-unit));
  --df-command-palette-item-padding-block: calc(2 * var(--spacing-unit));
  --df-command-palette-item-gap: calc(2.5 * var(--spacing-unit));
  --df-command-palette-footer-padding-inline: calc(3 * var(--spacing-unit));
  --df-command-palette-footer-padding-block: calc(2 * var(--spacing-unit));
  --df-command-palette-footer-gap: calc(3 * var(--spacing-unit));
  --df-command-palette-empty-padding: calc(8 * var(--spacing-unit));
  --df-command-palette-mark-bg: color-mix(
    in oklch,
    var(--primary) 16%,
    transparent
