  --df-command-palette-mark-fg: var(--foreground);

  --df-context-menu-min-width: var(--df-menu-min-width);
  --df-context-menu-max-width: var(--df-max-w-sm);
  --df-context-menu-padding: calc(1 * var(--spacing-unit));
  --df-context-menu-item-padding-inline: calc(3 * var(--spacing-unit));
  --df-context-menu-item-padding-block: calc(2 * var(--spacing-unit));
  --df-context-menu-item-gap: calc(2.5 * var(--spacing-unit));
  --df-context-menu-separator-margin-block: calc(1 * var(--spacing-unit));

  --df-date-picker-padding: calc(3 * var(--spacing-unit));
  --df-date-picker-gap: calc(2 * var(--spacing-unit));
  --df-date-picker-header-gap: calc(1.5 * var(--spacing-unit));
  --df-date-picker-day-size: var(--df-control-height-md);
  --df-date-picker-nav-size: var(--df-control-height-sm);
  --df-date-picker-weekday-size: var(--df-text-2xs);
  --df-date-picker-day-radius: var(--radius-md);
  --df-date-picker-range-bg: color-mix(
