  --df-checkbox-size-sm: var(--df-affordance-size-sm);
  --df-checkbox-size-md: var(--df-affordance-size-md);
  --df-checkbox-radius: var(--radius-xs);
  --df-checkbox-icon-size-sm: var(--df-affordance-size-2xs);
  --df-checkbox-icon-size-md: var(--df-affordance-size-xs);
  --df-checkbox-field-gap: calc(2.5 * var(--spacing-unit));
  --df-checkbox-copy-gap: calc(0.5 * var(--spacing-unit));

  --df-radio-size-sm: var(--df-affordance-size-sm);
  --df-radio-size-md: var(--df-affordance-size-md);
  --df-radio-dot-size-sm: var(--df-affordance-size-2xs);
  --df-radio-dot-size-md: var(--df-affordance-size-xs);
  --df-radio-field-gap: calc(2.5 * var(--spacing-unit));
  --df-radio-copy-gap: calc(0.5 * var(--spacing-unit));
  --df-radio-group-gap: calc(3 * var(--spacing-unit));
  --df-radio-group-items-gap: calc(2.5 * var(--spacing-unit));
